INSERT OR REPLACE INTO "question_bank" ("id", "subject", "type", "question", "options", "answer", "explanation", "score", "difficulty", "tags", "created_at") VALUES
  ('3376d8ee-0068-4c8d-815d-916001d9e929', '440', 'choice', '议程设置理论的提出者是？', '["A. \u674e\u666e\u66fc", "B. \u9ea6\u5e93\u59c6\u65af\u548c\u8096", "C. \u62c9\u624e\u65af\u83f2\u5c14\u5fb7", "D. \u8bfa\u4f9d\u66fc"]', 'B', '议程设置理论由麦库姆斯（McCombs）和肖（Shaw）在1972年教堂山研究中正式提出。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('05547478-16af-477c-af7c-c9367f8dd329', '440', 'choice', '议程设置理论的第二层次是指？', '["A. \u8bae\u9898\u663e\u8457\u6027", "B. \u5c5e\u6027\u663e\u8457\u6027", "C. \u7f51\u7edc\u8bae\u7a0b\u8bbe\u7f6e", "D. \u8bae\u7a0b\u878d\u5408\u7406\u8bba"]', 'B', '第二层次是属性议程设置，影响人们如何看待议题的特定属性。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('44e44cd4-2d78-465c-b732-27887f165fd0', '440', 'choice', '议程设置告诉人们''想什么''，框架理论告诉人们？', '["A. \u600e\u4e48\u60f3", "B. \u60f3\u591a\u5c11", "C. \u4f55\u65f6\u60f3", "D. \u4e3a\u8c01\u60f3"]', 'A', '框架理论告诉人们''怎么想''，即通过选择、强调和排除来建构报道框架。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('abbb4f43-ef20-4898-a530-7be43b866503', '440', 'choice', '沉默的螺旋理论提出的学者是？', '["A. \u683c\u4f2f\u7eb3", "B. \u970d\u5c14", "C. \u8bfa\u4f9d\u66fc", "D. \u5361\u8328"]', 'C', '沉默的螺旋由德国传播学者伊丽莎白·诺尔-诺依曼于1974年提出。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('49fc0223-a7af-4464-80b2-c23284bad941', '440', 'choice', '沉默的螺旋理论的核心假设不包括？', '["A. \u793e\u4f1a\u5bf9\u504f\u79bb\u7684\u6050\u60e7", "B. \u5bf9\u8206\u8bba\u7684\u6301\u7eed\u611f\u77e5", "C. \u516c\u5f00\u8868\u8fbe\u4e0e\u6c89\u9ed8\u7684\u503e\u5411", "D. \u53d7\u4f17\u7684\u4e3b\u52a8\u6027"]', 'D', '受众的主动性是使用与满足理论的核心，不是沉默的螺旋的假设。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('d5a4782e-15d4-47dd-92b3-34ea7dc0f6be', '440', 'choice', '沉默的螺旋在新媒体环境下？', '["A. \u5b8c\u5168\u5931\u6548", "B. \u4f9d\u7136\u9002\u7528\u4f46\u5f62\u5f0f\u53d8\u5316", "C. \u66f4\u52a0\u663e\u8457", "D. \u4e0e\u4f20\u7edf\u5a92\u4f53\u65e0\u5f02"]', 'B', '沉默的螺旋在新媒体环境下依然适用，但表现形式发生变化，如网络匿名性可能减弱沉默效应。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('40e507eb-856e-4615-8c7b-c8c975bf3cc1', '440', 'choice', '知沟理论的提出者是？', '["A. \u5361\u8328", "B. \u8482\u5947\u8bfa\u7b49", "C. \u7f57\u6770\u65af", "D. \u9ea6\u514b\u5362\u6c49"]', 'B', '知沟理论由蒂奇诺（Tichenor）等人于1970年提出。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('d77e2dbb-ce42-457e-a441-f5683d759444', '440', 'choice', '知沟理论认为信息差距会？', '["A. \u7f29\u5c0f", "B. \u6269\u5927", "C. \u4e0d\u53d8", "D. \u6d88\u5931"]', 'B', '知沟理论认为随着信息量增加，不同社会经济地位群体间的知识差距会扩大。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('35bd0c53-4c2e-411f-8b76-9712ce4b5dea', '440', 'choice', '使用与满足理论强调受众是？', '["A. \u88ab\u52a8\u7684", "B. \u4e3b\u52a8\u7684", "C. \u65e0\u610f\u8bc6\u7684", "D. \u88ab\u64cd\u7eb5\u7684"]', 'B', '使用与满足理论强调受众是主动的，基于自身需求选择和使用媒介。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('f542ab83-e4ea-4654-8a61-895dc08b5191', '440', 'choice', '使用与满足理论的四种需求不包括？', '["A. \u8ba4\u77e5\u9700\u6c42", "B. \u60c5\u611f\u9700\u6c42", "C. \u653f\u6cbb\u9700\u6c42", "D. \u793e\u4f1a\u6574\u5408\u9700\u6c42"]', 'C', '四种需求是：认知需求、情感需求、个人整合需求、社会整合需求。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('4b0b40bd-d45a-42ca-97f6-60616df74269', '440', 'choice', '把关人理论最初由哪位学者提出？', '["A. \u6000\u7279", "B. \u5362\u56e0", "C. \u62c9\u65af\u97e6\u5c14", "D. \u65bd\u62c9\u59c6"]', 'B', '把关人概念最初由库尔特·卢因（Lewin）于1947年提出。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('a62ca407-6064-4a18-aef1-89b9783f656f', '440', 'choice', '新媒体时代的把关特征是？', '["A. \u5355\u4e00\u628a\u5173", "B. \u53bb\u4e2d\u5fc3\u5316\u628a\u5173", "C. \u65e0\u628a\u5173", "D. \u653f\u5e9c\u628a\u5173"]', 'B', '新媒体时代呈现''去中心化把关''特征，算法、平台和用户都参与把关。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('0cf50c2d-86c6-401f-8046-e2dede248d07', '440', 'choice', '框架理论引入传播学的学者是？', '["A. \u6208\u592b\u66fc", "B. \u6069\u7279\u66fc", "C. \u9ea6\u514b\u5362\u6c49", "D. \u54c8\u8d1d\u9a6c\u65af"]', 'B', '戈夫曼提出框架概念，恩特曼将其引入传播学研究。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('09228c61-85f7-4280-8051-c57edfc0b3c5', '440', 'choice', '恩特曼提出框架的四个功能不包括？', '["A. \u754c\u5b9a\u95ee\u9898", "B. \u539f\u56e0\u89e3\u91ca", "C. \u4fe1\u606f\u7b5b\u9009", "D. \u5904\u7406\u5efa\u8bae"]', 'C', '四个功能是：界定问题、原因解释、道德判断、处理建议。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('5ccec6b6-131d-4081-be94-793ee2f9a865', '440', 'choice', '培养理论的提出者是？', '["A. \u8bfa\u4f9d\u66fc", "B. \u683c\u4f2f\u7eb3", "C. \u5361\u8328", "D. \u674e\u666e\u66fc"]', 'B', '培养理论由格伯纳（Gerbner）在1960年代提出。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('9b009414-5220-45a8-b2bd-e59a4156d91c', '440', 'choice', '培养理论认为重度电视观众的世界观？', '["A. \u66f4\u52a0\u5ba2\u89c2", "B. \u66f4\u63a5\u8fd1\u7535\u89c6\u5448\u73b0\u7684\u73b0\u5b9e", "C. \u4e0e\u8f7b\u5ea6\u89c2\u4f17\u65e0\u5f02", "D. \u66f4\u52a0\u60b2\u89c2"]', 'B', '培养理论认为重度电视观众的世界观会更接近电视所呈现的''符号现实''。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('6509f4a1-e514-4c8c-95bd-ce00b4e41f8d', '440', 'choice', '信息茧房概念由哪位学者提出？', '["A. \u6851\u65af\u5766", "B. \u9ea6\u514b\u5362\u6c49", "C. \u54c8\u8d1d\u9a6c\u65af", "D. \u7f57\u6770\u65af"]', 'A', '信息茧房由美国学者凯斯·桑斯坦在《信息乌托邦》中提出。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('174a0a42-502f-438c-99df-6afac7464e2b', '440', 'choice', '加剧信息茧房现象的主要因素是？', '["A. \u4f20\u7edf\u5a92\u4f53", "B. \u7b97\u6cd5\u63a8\u8350", "C. \u653f\u5e9c\u7ba1\u63a7", "D. \u6559\u80b2\u6c34\u5e73"]', 'B', '算法推荐根据用户偏好推送内容，加剧了信息茧房现象。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('2c546fc7-d102-45b3-afe6-43894d517af6', '440', 'choice', '编码/解码理论的提出者是？', '["A. \u798f\u67ef", "B. \u970d\u5c14", "C. \u5fb7\u91cc\u8fbe", "D. \u5df4\u7279"]', 'B', '编码/解码理论由斯图亚特·霍尔（Stuart Hall）于1973年提出。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('0d69b7de-9fee-44be-8b28-c88c6292ba7f', '440', 'choice', '以下哪种不是霍尔提出的解码立场？', '["A. \u4e3b\u5bfc\u5f0f\u89e3\u8bfb", "B. \u534f\u5546\u5f0f\u89e3\u8bfb", "C. \u5bf9\u6297\u5f0f\u89e3\u8bfb", "D. \u6d88\u8d39\u5f0f\u89e3\u8bfb"]', 'D', '三种解码立场是：主导式解读、协商式解读、对抗式解读。', 5, 'medium', NULL, '2026-06-09 12:47:23');

INSERT OR REPLACE INTO "question_bank" ("id", "subject", "type", "question", "options", "answer", "explanation", "score", "difficulty", "tags", "created_at") VALUES
  ('0f4f5f24-83f8-492d-81de-8ca11a451058', '440', 'choice', '公共领域理论的提出者是？', '["A. \u9a6c\u514b\u601d", "B. \u54c8\u8d1d\u9a6c\u65af", "C. \u97e6\u4f2f", "D. \u6d82\u5c14\u5e72"]', 'B', '公共领域理论由哈贝马斯（Habermas）于1962年提出。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('70712486-f5df-4315-8491-c4374122a53c', '440', 'choice', '公共领域的三个条件不包括？', '["A. \u5f00\u653e\u6027", "B. \u5e73\u7b49\u6027", "C. \u76c8\u5229\u6027", "D. \u7406\u6027\u8ba8\u8bba"]', 'C', '三个条件是：开放性、平等性、理性讨论。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('da141a01-c3d4-42cc-8b08-f9e072049952', '440', 'choice', '拟态环境概念的提出者是？', '["A. \u9ea6\u514b\u5362\u6c49", "B. \u674e\u666e\u66fc", "C. \u62c9\u65af\u97e6\u5c14", "D. \u65bd\u62c9\u59c6"]', 'B', '拟态环境由沃尔特·李普曼（Lippmann）于1922年提出。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('59265f3d-2ab6-4012-84fc-c658a2097ca9', '440', 'choice', '二级传播理论的提出者是？', '["A. \u7f57\u6770\u65af", "B. \u62c9\u624e\u65af\u83f2\u5c14\u5fb7", "C. \u5361\u8328", "D. \u970d\u592b\u5170"]', 'B', '二级传播理论由拉扎斯菲尔德（Lazarsfeld）于1944年提出。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('90a919ea-f049-496a-9e09-d4a0312e3cae', '440', 'choice', '二级传播理论认为信息传播的关键环节是？', '["A. \u5927\u4f17\u5a92\u4ecb", "B. \u610f\u89c1\u9886\u8896", "C. \u653f\u5e9c\u673a\u6784", "D. \u5546\u4e1a\u5e7f\u544a"]', 'B', '意见领袖在信息传播中起中介作用，是二级传播的关键环节。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('90535f48-4e8b-4923-9ef4-588b837740a0', '440', 'choice', '创新扩散理论的提出者是？', '["A. \u5361\u8328", "B. \u7f57\u6770\u65af", "C. \u62c9\u624e\u65af\u83f2\u5c14\u5fb7", "D. \u970d\u592b\u5170"]', 'B', '创新扩散理论由罗杰斯（Rogers）于1962年提出。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('c90f61d5-c725-4037-962e-fe2ef9e314c8', '440', 'choice', '创新扩散理论中最早采用新事物的群体是？', '["A. \u65e9\u671f\u591a\u6570", "B. \u521b\u65b0\u8005", "C. \u65e9\u671f\u91c7\u7528\u8005", "D. \u665a\u671f\u591a\u6570"]', 'B', '采用者分类：创新者→早期采用者→早期多数→晚期多数→落后者。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('b5b39da8-2475-4131-9693-590021908377', '440', 'choice', '第三人效果理论的提出者是？', '["A. \u8bfa\u4f9d\u66fc", "B. \u6234\u7ef4\u68ee", "C. \u683c\u4f2f\u7eb3", "D. \u5361\u8328"]', 'B', '第三人效果由戴维森（Davison）于1983年提出。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('cf83b038-c72f-4b55-9984-937f2e91f1af', '440', 'choice', '第三人效果认为人们倾向于认为媒体对谁的影响更大？', '["A. \u81ea\u5df1", "B. \u4ed6\u4eba", "C. \u653f\u5e9c", "D. \u5a92\u4f53\u81ea\u8eab"]', 'B', '人们倾向于认为大众传播媒介对别人的影响比对自己的影响更大。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('d45fcef7-73eb-4062-87a1-5d6b35fe5e6b', '440', 'choice', '数字鸿沟的三个层次不包括？', '["A. \u63a5\u5165\u9e3f\u6c9f", "B. \u4f7f\u7528\u9e3f\u6c9f", "C. \u77e5\u8bc6\u9e3f\u6c9f", "D. \u60c5\u611f\u9e3f\u6c9f"]', 'D', '三个层次是：接入鸿沟、使用鸿沟、知识鸿沟。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('e51e5571-bc41-4639-aaad-9ae78a5a9582', '440', 'choice', '''媒介即讯息''的提出者是？', '["A. \u674e\u666e\u66fc", "B. \u9ea6\u514b\u5362\u6c49", "C. \u54c8\u8d1d\u9a6c\u65af", "D. \u683c\u4f2f\u7eb3"]', 'B', '''媒介即讯息''由马歇尔·麦克卢汉（McLuhan）于1964年提出。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('e3a502fb-2388-47a3-b69b-10ba1cc4616e', '440', 'choice', '传播仪式观的提出者是？', '["A. \u970d\u5c14", "B. \u51ef\u745e", "C. \u9ea6\u514b\u5362\u6c49", "D. \u674e\u666e\u66fc"]', 'B', '传播仪式观由詹姆斯·凯瑞（Carey）于1989年提出。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('5b90a7e3-6c0b-4a99-b61b-baaa62e42fbb', '440', 'choice', '新闻专业主义的核心要素不包括？', '["A. \u5ba2\u89c2\u6027", "B. \u516c\u6b63\u6027", "C. \u76c8\u5229\u6027", "D. \u72ec\u7acb\u6027"]', 'C', '核心要素是：客观性、公正性、独立性、自由性。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('fa556563-3e6e-4e0b-8f4a-88bdd599ecc2', '440', 'choice', '以下哪个不是媒介融合的模式？', '["A. \u4e2d\u592e\u53a8\u623f", "B. \u53bf\u7ea7\u878d\u5a92\u4f53", "C. \u5168\u5a92\u4f53\u4f20\u64ad\u4f53\u7cfb", "D. \u4f20\u7edf\u5a92\u4f53\u72ec\u7acb\u8fd0\u8425"]', 'D', '媒介融合模式包括中央厨房、县级融媒体、全媒体传播体系。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('6207dfa6-7e04-4095-a004-915a95851058', '440', 'choice', '新闻价值五要素不包括？', '["A. \u65f6\u65b0\u6027", "B. \u91cd\u8981\u6027", "C. \u76c8\u5229\u6027", "D. \u8da3\u5473\u6027"]', 'C', '五要素是：时新性、重要性、显著性、接近性、趣味性。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('d41f6252-7aa6-40c1-86fa-b50c42b475a4', '440', 'short_answer', '简述议程设置理论的三个层次及其新媒体环境下的发展。', NULL, '三个层次：1.议题议程设置（第一层）：媒体影响人们关注哪些议题；2.属性议程设置（第二层）：影响人们如何看待议题的特定属性；3.网络议程设置（第三层）：影响要素之间的关联网络。新媒体环境下发展：议程融合理论认为受众在社交媒体中主动寻求信息来满足归属需求，议程设置从单向变为双向互动。', '需要答出三个层次的名称和简要解释，以及新媒体环境下的发展。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('0e5cad73-504d-46bb-8223-00df78e52ceb', '440', 'short_answer', '简述传播学经验学派与批判学派的区别。', NULL, '区别：1.研究目的：经验学派关注效果和功能，批判学派关注权力和意识形态；2.研究方法：经验学派偏重定量、实证，批判学派偏重定性、思辨；3.理论立场：经验学派维护现有体制，批判学派质疑和批判现有体制；4.学科背景：经验学派源于美国社会学，批判学派源于欧洲哲学。', '从研究目的、方法、立场、背景四个角度对比。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('9c3db1e7-1fcf-48ca-96ab-c26fdffeaa61', '440', 'short_answer', '简述沉默的螺旋理论的核心观点和三个假设。', NULL, '核心观点：人们在表达观点时会观察舆论环境，如果发现自己的观点属于少数派，出于被孤立的恐惧，会倾向于沉默。三个假设：1.社会对偏离的恐惧；2.对舆论的持续感知；3.公开表达与沉默的倾向。', '需要答出核心观点和三个假设。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('bfa6ce00-5aaa-4391-bfa8-7216c0537dd7', '440', 'short_answer', '简述知沟理论的主要内容和影响因素。', NULL, '主要内容：随着大众传播的信息量增加，社会经济地位较高的人获取知识的速度快于地位低的人，两者之间的知识差距会扩大。影响因素：传播技能、信息储备、社会交往、选择性接触、媒介性质。', '需要答出主要内容和影响因素。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('76d670ea-0976-4458-bbac-2c90e869ac54', '440', 'short_answer', '简述使用与满足理论的主要内容和四种需求。', NULL, '主要内容：受众是主动的，基于特定需求选择和使用媒介来获得满足。四种需求：1.认知需求（获取信息知识）；2.情感需求（审美体验）；3.个人整合需求（自信地位）；4.社会整合需求（社交联系）。', '需要答出核心观点和四种需求。', 15, 'medium', NULL, '2026-06-09 12:47:23');

INSERT OR REPLACE INTO "question_bank" ("id", "subject", "type", "question", "options", "answer", "explanation", "score", "difficulty", "tags", "created_at") VALUES
  ('43295be0-cea3-4001-b5a4-a77202950583', '440', 'short_answer', '简述把关人理论在新媒体时代的变化。', NULL, '传统媒体时代编辑是主要把关人，新媒体时代发生以下变化：1.把关权转移：从专业编辑转向算法、平台和用户；2.去中心化把关：多个主体参与把关过程；3.算法把关：推荐算法成为重要把关机制；4.用户把关：用户通过点赞、分享等行为参与把关。', '需要答出传统把关和新媒体把关的区别。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('ecfba75b-ad36-41d0-8293-a0b870a052dc', '440', 'short_answer', '简述框架理论与议程设置理论的联系与区别。', NULL, '联系：两者都关注媒体对受众认知的影响。区别：1.影响层面不同：议程设置影响''想什么''，框架理论影响''怎么想''；2.作用机制不同：议程设置通过显著性转移，框架理论通过选择、强调和排除；3.研究层次不同：议程设置关注议题层面，框架理论关注属性层面。', '需要答出联系和区别。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('fb9770e6-bcdc-4458-8971-e6e702e7556a', '440', 'short_answer', '简述培养理论的主要内容和核心概念。', NULL, '主要内容：大众传媒通过长期的、潜移默化的影响，会塑造受众对现实世界的认知。核心概念：1.主流化：重度电视观众的世界观趋于一致；2.共鸣：电视内容与个人经历一致时效果增强；3.第一级信念/第二级信念：对具体事实和整体世界观的影响。', '需要答出主要内容和核心概念。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('2cedf883-88b9-4cc8-9ecd-e4ec405bca46', '440', 'short_answer', '简述编码/解码理论的三种解码立场。', NULL, '三种解码立场：1.主导式解读（霸权式）：按传播者意图理解，完全接受编码意义；2.协商式解读：部分接受、部分修改，根据自身立场进行调整；3.对抗式解读：完全反向理解，识别编码意图但以相反立场解读。', '需要答出三种立场及其特点。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('7c417aeb-0dd3-49f6-bdf1-bbc61bc83ffa', '440', 'short_answer', '简述公共领域理论在新媒体时代的适用性。', NULL, '适用性分析：积极方面——社交媒体拓展了公共讨论空间，降低了参与门槛，增强了互动性。消极方面——信息碎片化、情绪化表达、群体极化等问题削弱了理性讨论的条件。结论：新媒体重构了公共领域的形态，但其核心条件（开放性、平等性、理性讨论）仍面临挑战。', '需要从正反两方面分析。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('550d8943-3e78-4730-aa5e-fb108cfd5822', '440', 'short_answer', '简述信息茧房的形成机制和应对策略。', NULL, '形成机制：1.个体选择性接触：只关注自己感兴趣的信息；2.算法推荐：根据用户偏好推送相似内容；3.社交圈层化：与相似观点的人互动。应对策略：1.提升媒介素养；2.主动拓展信息来源；3.算法优化：增加多样性推荐；4.政策监管：规范算法推荐行为。', '需要答出形成机制和应对策略。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('27f7e8a2-ea67-4d61-8273-370d64378d68', '440', 'short_answer', '简述数字鸿沟的三个层次及其表现。', NULL, '三个层次：1.接入鸿沟：设备和网络接入差距，城乡、区域间差异；2.使用鸿沟：数字技能和使用能力差距，老年人、低教育群体面临障碍；3.知识鸿沟：从信息中获取知识的差距，信息素养差异导致知识获取不平等。', '需要答出三个层次及其具体表现。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('3a1bc8cf-1455-4acc-839b-a7d468c92e4a', '334', 'choice', '新闻价值五要素不包括以下哪项？', '["A. \u65f6\u65b0\u6027", "B. \u91cd\u8981\u6027", "C. \u76c8\u5229\u6027", "D. \u63a5\u8fd1\u6027"]', 'C', '新闻价值五要素：时新性、重要性、显著性、接近性、趣味性。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('c96d47d2-c60b-4cbf-94c3-40b722fae5c7', '334', 'choice', '新闻采访中最常用的方法是？', '["A. \u89c2\u5bdf\u6cd5", "B. \u8bbf\u8c08\u6cd5", "C. \u95ee\u5377\u6cd5", "D. \u5b9e\u9a8c\u6cd5"]', 'B', '访谈法是新闻采访中最常用、最基本的方法。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('388d7354-34e6-4a9e-8e9a-5628ac73cb83', '334', 'choice', '新闻标题制作的首要原则是？', '["A. \u751f\u52a8\u6709\u8da3", "B. \u51c6\u786e\u771f\u5b9e", "C. \u7b80\u6d01\u660e\u4e86", "D. \u5438\u5f15\u773c\u7403"]', 'B', '准确真实是新闻标题制作的首要原则。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('32b44d8c-c4d9-491d-afb2-776bb8bf4d9d', '334', 'choice', '消息写作中最常用的结构是？', '["A. \u5012\u91d1\u5b57\u5854\u7ed3\u6784", "B. \u91d1\u5b57\u5854\u7ed3\u6784", "C. \u5e76\u5217\u7ed3\u6784", "D. \u65f6\u95f4\u987a\u5e8f\u7ed3\u6784"]', 'A', '倒金字塔结构是消息写作中最常用的结构，把最重要的信息放在最前面。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('cba0bff5-c61c-44fd-9d3e-cda93d30e9c9', '334', 'choice', '新闻评论的三要素是？', '["A. \u8bba\u70b9\u3001\u8bba\u636e\u3001\u8bba\u8bc1", "B. \u6807\u9898\u3001\u5bfc\u8bed\u3001\u6b63\u6587", "C. \u4f55\u65f6\u3001\u4f55\u5730\u3001\u4f55\u4eba", "D. \u4e8b\u5b9e\u3001\u89c2\u70b9\u3001\u7ed3\u8bba"]', 'A', '新闻评论的三要素是论点、论据、论证。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('71f61785-cccf-4840-82a1-43ae4294af5d', '334', 'choice', '深度报道的核心特征是？', '["A. \u65f6\u6548\u6027\u5f3a", "B. \u6df1\u5165\u8c03\u67e5\u548c\u5206\u6790", "C. \u7bc7\u5e45\u77ed\u5c0f", "D. \u5a31\u4e50\u6027\u5f3a"]', 'B', '深度报道的核心特征是深入调查和分析，揭示事件背后的原因和意义。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('e45cd815-5763-4f76-9815-c5f7866010be', '334', 'choice', '新闻敏感又称为？', '["A. \u65b0\u95fb\u55c5\u89c9", "B. \u65b0\u95fb\u89d2\u5ea6", "C. \u65b0\u95fb\u4ef7\u503c", "D. \u65b0\u95fb\u7ebf\u7d22"]', 'A', '新闻敏感又称新闻嗅觉、新闻鼻，是记者发现和判断新闻的能力。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('d1e3687b-2809-4f29-ba92-b08920334d2a', '334', 'choice', '以下哪种不属于新闻采访的观察法类型？', '["A. \u53c2\u4e0e\u89c2\u5bdf", "B. \u975e\u53c2\u4e0e\u89c2\u5bdf", "C. \u95ee\u5377\u89c2\u5bdf", "D. \u9690\u853d\u89c2\u5bdf"]', 'C', '观察法类型包括参与观察、非参与观察、隐蔽观察、公开观察。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('d2bb487f-7531-4281-a86c-9592628c5943', '334', 'choice', '新闻编辑的核心职能是？', '["A. \u91c7\u8bbf", "B. \u628a\u5173", "C. \u7ecf\u8425", "D. \u53d1\u884c"]', 'B', '新闻编辑的核心职能是把关，对新闻内容进行筛选、加工和审核。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('55c7eacb-1002-42d0-bc27-534963397de5', '334', 'choice', '广告传播的AIDMA模型中，A代表？', '["A. Action", "B. Attention", "C. Attitude", "D. Appeal"]', 'B', 'AIDMA：Attention（注意）→Interest（兴趣）→Desire（欲望）→Memory（记忆）→Action（行动）。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('f055aeee-d1a6-4a4b-ac04-43407a7d35ef', '334', 'choice', '公共关系的核心目标是？', '["A. \u9500\u552e\u4ea7\u54c1", "B. \u5efa\u7acb\u826f\u597d\u5173\u7cfb", "C. \u5371\u673a\u5904\u7406", "D. \u5a92\u4f53\u66dd\u5149"]', 'B', '公共关系的核心目标是组织与公众之间建立和维护良好关系。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('49aad9bf-72ff-41f6-a3b9-8fc3298dc45f', '334', 'choice', '危机公关的5S原则不包括？', '["A. \u627f\u62c5\u8d23\u4efb", "B. \u771f\u8bda\u6c9f\u901a", "C. \u901f\u5ea6\u7b2c\u4e00", "D. \u5229\u6da6\u6700\u5927\u5316"]', 'D', '5S原则：承担责任、真诚沟通、速度第一、系统运行、权威证实。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('2657246a-99ed-4b1c-ab3f-7f567c650b7f', '334', 'choice', '媒介融合最早由谁提出？', '["A. \u5c3c\u845b\u6d1b\u5e9e\u5e1d", "B. \u9ea6\u514b\u5362\u6c49", "C. \u674e\u666e\u66fc", "D. \u54c8\u8d1d\u9a6c\u65af"]', 'A', '媒介融合概念最早由尼葛洛庞帝（Negroponte）提出。', 5, 'medium', NULL, '2026-06-09 12:47:23');

INSERT OR REPLACE INTO "question_bank" ("id", "subject", "type", "question", "options", "answer", "explanation", "score", "difficulty", "tags", "created_at") VALUES
  ('ac6f1a5e-9dbb-468d-b908-b685b58cbe4b', '334', 'choice', '县级融媒体中心建设始于哪一年？', '["A. 2016\u5e74", "B. 2018\u5e74", "C. 2020\u5e74", "D. 2022\u5e74"]', 'B', '2018年8月，全国宣传思想工作会议提出县级融媒体中心建设。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('0c21d3a0-cf4d-4a49-bda5-0ac582b9b908', '334', 'choice', '''四全媒体''理念由谁提出？', '["A. \u4e60\u8fd1\u5e73", "B. \u80e1\u9526\u6d9b", "C. \u6c5f\u6cfd\u6c11", "D. \u9093\u5c0f\u5e73"]', 'A', '2019年1月，习近平在中央政治局集体学习时提出''四全媒体''理念。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('924b5a97-e19f-4124-a0ae-2bfad696c478', '334', 'choice', '数据新闻的核心特征是？', '["A. \u6570\u636e\u9a71\u52a8", "B. \u5a31\u4e50\u5316", "C. \u77ed\u5c0f\u7cbe\u608d", "D. \u89c6\u89c9\u5316"]', 'A', '数据新闻的核心特征是数据驱动，通过数据挖掘、分析和可视化来讲故事。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('8a087e43-9dbd-4f84-885b-047a14c4cfb1', '334', 'choice', '新闻真实性要求不包括？', '["A. \u5177\u4f53\u771f\u5b9e", "B. \u6574\u4f53\u771f\u5b9e", "C. \u672c\u8d28\u771f\u5b9e", "D. \u4e3b\u89c2\u771f\u5b9e"]', 'D', '新闻真实性要求具体真实、整体真实、本质真实，不包括主观真实。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('94f96d12-28e3-49c8-bbba-014287589452', '334', 'choice', '新闻自由的提出与哪部文献有关？', '["A. \u300a\u4eba\u6743\u5ba3\u8a00\u300b", "B. \u300a\u8bba\u81ea\u7531\u300b", "C. \u300a\u62a5\u520a\u7684\u56db\u79cd\u7406\u8bba\u300b", "D. \u300a\u72ec\u7acb\u5ba3\u8a00\u300b"]', 'C', '《报刊的四种理论》（1956年）系统阐述了新闻自由的理论框架。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('8fed1990-29d6-437b-a025-4426215cc48b', '334', 'choice', '网络直播的传播特征不包括？', '["A. \u5373\u65f6\u6027", "B. \u4e92\u52a8\u6027", "C. \u6df1\u5ea6\u6027", "D. \u788e\u7247\u5316"]', 'C', '网络直播特征：即时性、互动性、碎片化、娱乐性，不包括深度性。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('f154085a-f9ee-4c4f-bbce-01e0e961a224', '334', 'choice', '算法推荐的核心机制是？', '["A. \u4eba\u5de5\u7f16\u8f91", "B. \u7528\u6237\u753b\u50cf\u5339\u914d", "C. \u968f\u673a\u63a8\u9001", "D. \u65f6\u95f4\u6392\u5e8f"]', 'B', '算法推荐通过用户画像匹配实现个性化内容推送。', 5, 'medium', NULL, '2026-06-09 12:47:23'),
  ('80132cb3-11f7-4cf1-a871-319767e8e964', '334', 'short_answer', '简述新闻采访中观察法的类型和应用。', NULL, '观察法类型：1.参与观察：记者深入采访对象的生活环境进行观察；2.非参与观察：记者以旁观者身份观察；3.隐蔽观察：不暴露记者身份的观察；4.公开观察：暴露身份的观察。应用场景：现场报道、体验式采访、调查性报道、人物特写等。', '需要答出观察法的主要类型和具体应用场景。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('ac4380d5-3129-4f1a-8e84-38ab5193ba37', '334', 'short_answer', '简述新闻评论的论证方法。', NULL, '主要论证方法：1.例证法：用具体事例证明论点；2.引证法：引用权威观点或数据；3.对比法：通过对比突出论点；4.类比法：用相似事物进行类比推理；5.归谬法：假设对方观点成立，推导出荒谬结论。', '需要答出主要论证方法及其特点。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('3d740653-255f-4eeb-9ff6-10ee17452bb2', '334', 'short_answer', '简述新闻价值的五个要素。', NULL, '五个要素：1.时新性：事件发生时间近、内容新；2.重要性：影响范围大、涉及人数多；3.显著性：人物/地点知名度高；4.接近性：地理或心理上的接近；5.趣味性：人情味、新奇性。', '需要答出五个要素及其含义。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('c63e52f0-0952-4140-8ff5-9c1fb95e9b35', '334', 'short_answer', '简述消息写作的倒金字塔结构。', NULL, '倒金字塔结构是消息写作中最常用的结构，特点：1.把最重要、最新鲜的事实放在最前面（导语）；2.按重要性递减的顺序安排材料；3.读者可以随时停止阅读而不遗漏关键信息。优点：便于编辑删节、突出重点、符合阅读习惯。', '需要答出结构特点和优点。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('3fed6b84-fff1-44a6-8e9d-bc7c574789f3', '334', 'short_answer', '简述新闻专业主义的核心要素。', NULL, '核心要素：1.客观性：报道事实，避免主观倾向；2.公正性：平衡呈现各方观点；3.独立性：不受政治、经济等力量干预；4.自由性：保障新闻采访报道自由。新媒体时代面临的挑战：公民新闻兴起、算法推荐影响、流量导向冲击。', '需要答出核心要素和面临的挑战。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('7817d30a-7cfd-40d7-ba34-317ccb5e4e42', '334', 'short_answer', '简述深度报道的特点和类型。', NULL, '特点：1.深入调查和分析；2.揭示事件背后的原因和意义；3.篇幅较长、信息量大。类型：1.解释性报道：解释事件原因和背景；2.调查性报道：揭露被隐藏的事实；3.预测性报道：分析事件发展趋势；4.精确新闻：用社会科学方法报道新闻。', '需要答出特点和主要类型。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('f2042233-f594-485d-8ee1-bb5534dcef97', '334', 'short_answer', '简述媒介融合的主要模式。', NULL, '主要模式：1.中央厨房模式：一次采集、多种生成、多元传播；2.县级融媒体中心：整合县级媒体资源；3.全媒体传播体系：全程、全息、全员、全效。特点：内容融合、渠道融合、平台融合、经营融合、管理融合。', '需要答出主要模式和特点。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('e27b9aeb-3187-46b9-af07-f7fda982c948', '334', 'short_answer', '简述危机公关的5S原则。', NULL, '5S原则：1.承担责任（Shoulder）：主动承担责任；2.真诚沟通（Sincerity）：与公众真诚沟通；3.速度第一（Speed）：快速响应；4.系统运行（System）：统一口径、系统应对；5.权威证实（Standard）：用权威证据说话。', '需要答出5S原则的具体内容。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('e5c28064-7b48-47f3-ac06-0096e75ca7c0', '334', 'short_answer', '简述数据新闻的生产流程。', NULL, '生产流程：1.数据搜集：从公开数据库、爬虫等获取数据；2.数据清洗：处理缺失值、异常值；3.数据分析：运用统计方法发现规律；4.数据可视化：用图表、地图等呈现；5.故事讲述：将数据转化为新闻故事。', '需要答出完整的生产流程。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('34bd2682-3fa9-40e8-bdb9-48043957c62d', '334', 'short_answer', '简述网络直播的传播特征。', NULL, '传播特征：1.即时性：实时传播，现场感强；2.互动性：弹幕、打赏等互动方式；3.碎片化：内容碎片化、时间碎片化；4.娱乐化：以娱乐内容为主；5.商业性：直播带货等商业模式。', '需要答出主要传播特征。', 15, 'medium', NULL, '2026-06-09 12:47:23'),
  ('a549d5aa-a5b5-4a84-bd95-f1aef5c9dc0f', '440', 'essay', '结合传播学理论，分析短视频平台的传播机制与社会影响。', NULL, '1.传播机制：算法推荐+社交分发+内容池；2.使用与满足视角：满足娱乐、社交、自我表达需求；3.培养理论视角：长期接触影响价值观和行为模式；4.信息茧房：算法推荐导致信息窄化；5.社会影响：文化传播、经济带动、注意力碎片化、青少年保护。', '需要结合具体传播学理论分析，有正面和负面分析。', 30, 'medium', NULL, '2026-06-09 12:47:23'),
  ('498b128a-5544-4956-8be1-62a893e00e0c', '440', 'essay', '结合实例论述人工智能对新闻生产的影响及伦理挑战。', NULL, '1.影响：自动写作、智能编辑、个性化分发、事实核查辅助；2.效率提升：降低成本、加快速度、扩大覆盖面；3.伦理挑战：真实性危机、算法偏见、版权争议、就业冲击；4.案例：腾讯Dreamwriter、新华社AI主播；5.应对：人机协作、伦理规范、技术治理。', '需要有具体案例、正反分析、伦理讨论。', 30, 'medium', NULL, '2026-06-09 12:47:23'),
  ('f99285ca-43e4-4b07-abb6-1e91ae870b65', '440', 'essay', '论述中国主流媒体如何在国际传播中提升话语权。', NULL, '1.当前困境：有理说不出、说了传不开；2.原因分析：话语体系差异、文化折扣、传播渠道不足；3.策略：构建中国话语体系、创新对外传播方式、善用新媒体平台；4.案例：CGTN、新华社海外社交媒体运营；5.路径：文明交流互鉴、技术赋能、人才培养。', '需要有分析、策略和案例。', 30, 'medium', NULL, '2026-06-09 12:47:23');

INSERT OR REPLACE INTO "question_bank" ("id", "subject", "type", "question", "options", "answer", "explanation", "score", "difficulty", "tags", "created_at") VALUES
  ('c603239f-097e-4be8-8fec-32d46681871c', '440', 'essay', '论述媒体深度融合的路径与趋势。', NULL, '1.三个阶段：相加→相融→深度融合；2.中央厨房模式：一次采集、多种生成、多元传播；3.县级融媒体中心：打通最后一公里；4.四全媒体：全程、全息、全员、全效；5.挑战：体制机制、人才短缺、盈利模式。', '需要有阶段分析、模式解读和挑战讨论。', 30, 'medium', NULL, '2026-06-09 12:47:23'),
  ('c0ffbca6-ebe1-47ca-86ae-42e7d5692f83', '440', 'essay', '结合实例分析社交媒体对公共舆论的影响。', NULL, '1.积极影响：拓展公共讨论空间、降低参与门槛、增强互动性；2.消极影响：信息碎片化、情绪化表达、群体极化、网络暴力；3.理论分析：沉默的螺旋、议程设置、公共领域；4.案例：微博热搜事件；5.治理建议：提升媒介素养、平台责任、法律规范。', '需要结合理论和案例进行正反分析。', 30, 'medium', NULL, '2026-06-09 12:47:23'),
  ('ddbfd113-0798-4b50-8ec9-cc5ff0567c7f', '440', 'essay', '分析算法推荐对新闻专业主义的冲击。', NULL, '1.冲击：把关权转移、信息茧房、流量导向、真实性挑战；2.具体表现：算法偏好导致内容低俗化、个性化推送窄化信息视野；3.理论分析：把关人理论、信息茧房、议程设置；4.应对策略：算法透明、人工审核、媒介素养提升；5.平衡：效率与公平、个性与多元。', '需要有冲击分析、理论支撑和应对策略。', 30, 'medium', NULL, '2026-06-09 12:47:23'),
  ('6fb64b1a-5ee8-4e0a-9aad-81ef0f492ea6', '440', 'essay', '论述新技术对新闻生产的影响。', NULL, '1.AI技术：自动写作、智能编辑、事实核查；2.VR/AR技术：沉浸式新闻、虚拟演播室；3.大数据技术：数据新闻、精准推送；4.区块链技术：新闻版权保护、信息溯源；5.影响：效率提升、形式创新、伦理挑战、人才需求变化。', '需要涵盖多种技术及其影响。', 30, 'medium', NULL, '2026-06-09 12:47:23'),
  ('2df723ab-42d3-4d5f-ae7b-632c46c2651b', '440', 'essay', '论述社交媒体时代的公共领域重构。', NULL, '1.哈贝马斯公共领域理论：开放性、平等性、理性讨论；2.社交媒体的重构：微博成为舆论场、微信公众号形成信息分发新渠道；3.积极影响：讨论空间扩大、参与门槛降低；4.消极影响：碎片化、情绪化、群体极化；5.构建理性公共讨论的路径。', '需要有理论基础和现实分析。', 30, 'medium', NULL, '2026-06-09 12:47:23');
